import{_ as l,o as t,c as o,a2 as i}from"./chunks/framework.Bjylvv1V.js";const u=JSON.parse('{"title":"전출입 처리","description":"","frontmatter":{},"headers":[],"relativePath":"guide/scenarios/move-in-out.md","filePath":"guide/scenarios/move-in-out.md","lastUpdated":1771991831000}'),e={name:"guide/scenarios/move-in-out.md"};function r(s,a,n,h,c,p){return t(),o("div",null,[...a[0]||(a[0]=[i(`<h1 id="전출입-처리" tabindex="-1">전출입 처리 <a class="header-anchor" href="#전출입-처리" aria-label="Permalink to &quot;전출입 처리&quot;">​</a></h1><blockquote><p><strong>소요 시간</strong>: 건당 약 15분 | <strong>난이도</strong>: ★★☆ | <strong>주기</strong>: 수시 (전출입 발생 시)</p></blockquote><p>세대 소유자/임차인의 전입(입주)과 전출(퇴거)을 처리하고, 중간정산·장기수선충당금 정산을 수행하는 프로세스입니다.</p><h2 id="전체-흐름" tabindex="-1">전체 흐름 <a class="header-anchor" href="#전체-흐름" aria-label="Permalink to &quot;전체 흐름&quot;">​</a></h2><h3 id="전입-입주-처리" tabindex="-1">전입(입주) 처리 <a class="header-anchor" href="#전입-입주-처리" aria-label="Permalink to &quot;전입(입주) 처리&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 이전 세대주 전출 확인   (1분)  → 전출 처리 완료 여부 확인</span></span>
<span class="line"><span>2. 신규 입주자 등록        (5분)  → 세대 정보·가족·차량 입력</span></span>
<span class="line"><span>3. 관리비예치금 처리       (3분)  → 선수관리비 입금 확인</span></span>
<span class="line"><span>4. 부과 기준 반영          (1분)  → 부과그룹·자동이체 확인</span></span></code></pre></div><h3 id="전출-퇴거-처리" tabindex="-1">전출(퇴거) 처리 <a class="header-anchor" href="#전출-퇴거-처리" aria-label="Permalink to &quot;전출(퇴거) 처리&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 미납 확인              (2분)  → 체납 관리비 정리</span></span>
<span class="line"><span>2. 장기수선충당금 정산     (5분)  → 환급액 계산</span></span>
<span class="line"><span>3. 전출 처리 실행         (3분)  → 중간관리비 정산</span></span>
<span class="line"><span>4. 관리비예치금 환급       (3분)  → 선수관리비 반환</span></span>
<span class="line"><span>5. 차량·카드 정리         (2분)  → 출입카드·차량 등록 해제</span></span></code></pre></div><hr><h2 id="전입-입주-처리-1" tabindex="-1">전입(입주) 처리 <a class="header-anchor" href="#전입-입주-처리-1" aria-label="Permalink to &quot;전입(입주) 처리&quot;">​</a></h2><h3 id="_1단계-이전-세대주-전출-확인-1분" tabindex="-1">1단계: 이전 세대주 전출 확인 (1분) <a class="header-anchor" href="#_1단계-이전-세대주-전출-확인-1분" aria-label="Permalink to &quot;1단계: 이전 세대주 전출 확인 (1분)&quot;">​</a></h3><div class="warning custom-block"><p class="custom-block-title">전출 먼저</p><p>이전 세대주의 전출 처리가 완료되어야 새 입주자를 등록할 수 있습니다.</p></div><p><a href="/recp/">수납</a> &gt; <a href="/recp/overdue.html">미납조회</a>에서 해당 세대의 미납이 모두 정리되었는지 확인합니다.</p><h3 id="_2단계-신규-입주자-등록-5분" tabindex="-1">2단계: 신규 입주자 등록 (5분) <a class="header-anchor" href="#_2단계-신규-입주자-등록-5분" aria-label="Permalink to &quot;2단계: 신규 입주자 등록 (5분)&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 입주자 &gt; <a href="/occp/move-in.html">입주처리</a> &gt; 입주등록 (OCCP1010)</p></blockquote><h4 id="절차" tabindex="-1">절차 <a class="header-anchor" href="#절차" aria-label="Permalink to &quot;절차&quot;">​</a></h4><ol><li>입주등록 화면 진입</li><li>조건 검색 (동·호수·상태)으로 해당 세대 찾기</li><li>세대 선택 → <strong>수정</strong> 클릭</li><li>기본 정보 입력: <ul><li><strong>직업/일반 구분</strong> 선택</li><li><strong>입주 상태</strong> 탭: 소유자/임차인 구분, 입주일</li><li><strong>가족 구성원</strong> 탭: 동거인 정보</li><li><strong>차량</strong> 탭: 차량 등록</li><li><strong>반려동물</strong> 탭: 해당 시 입력</li><li><strong>임대 정보</strong> 탭: 임차인인 경우 계약 정보</li></ul></li><li>소유자와 입주자가 다르면 별도 입력</li><li><strong>저장</strong></li></ol><h4 id="대량-등록-엑셀" tabindex="-1">대량 등록 (엑셀) <a class="header-anchor" href="#대량-등록-엑셀" aria-label="Permalink to &quot;대량 등록 (엑셀)&quot;">​</a></h4><p>신규 단지 등 대량 입주 시:</p><ol><li>엑셀 템플릿 다운로드</li><li>동, 호수 등 정보 입력</li><li>파일 형식: <strong>Excel 97-2003(.xls)</strong></li><li>업로드 실행</li></ol><div class="warning custom-block"><p class="custom-block-title">개인정보 동의</p><p>입주자 등록 전에 <strong>개인정보 수집·이용 동의서</strong>를 반드시 받으세요. <a href="/occp/privacy.html">개인정보</a> 관리 기능을 활용할 수 있습니다.</p></div><h3 id="_3단계-관리비예치금-처리-3분" tabindex="-1">3단계: 관리비예치금 처리 (3분) <a class="header-anchor" href="#_3단계-관리비예치금-처리-3분" aria-label="Permalink to &quot;3단계: 관리비예치금 처리 (3분)&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 입주자 &gt; <a href="/occp/move-in.html">입주처리</a> &gt; 관리비예치금(선수관리) (OCCP1040)</p></blockquote><p>입주 시 납부하는 관리비 예치금(선수관리비)을 등록합니다.</p><ol><li>해당 세대 선택</li><li>예치금 금액 등록</li><li>입금 확인 후 납부 상태 변경</li><li>필요 시 예치금 안내서·영수증 출력</li></ol><h3 id="_4단계-부과-기준-반영-1분" tabindex="-1">4단계: 부과 기준 반영 (1분) <a class="header-anchor" href="#_4단계-부과-기준-반영-1분" aria-label="Permalink to &quot;4단계: 부과 기준 반영 (1분)&quot;">​</a></h3><ul><li><a href="/impo/basic.html">기초정보</a>에서 해당 세대가 올바른 <strong>부과그룹</strong>에 포함되어 있는지 확인</li><li><strong>자동이체</strong> 신청 세대는 자동이체세대등록(IMPO1060) 확인</li><li><strong>부과제외</strong> 해제 필요 시 부과제외세대등록(IMPO1040) 확인</li></ul><hr><h2 id="전출-퇴거-처리-1" tabindex="-1">전출(퇴거) 처리 <a class="header-anchor" href="#전출-퇴거-처리-1" aria-label="Permalink to &quot;전출(퇴거) 처리&quot;">​</a></h2><h3 id="_1단계-미납-확인-2분" tabindex="-1">1단계: 미납 확인 (2분) <a class="header-anchor" href="#_1단계-미납-확인-2분" aria-label="Permalink to &quot;1단계: 미납 확인 (2분)&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 수납 &gt; <a href="/recp/overdue.html">미납조회</a> &gt; 미납대장 (RECP5070)</p></blockquote><p>해당 세대의 미납 관리비를 확인합니다.</p><div class="danger custom-block"><p class="custom-block-title">미납 정리 필수</p><p>미납이 있으면 전출 처리를 진행할 수 없습니다. 전출 전에 모든 체납 관리비를 정산하세요.</p></div><h3 id="_2단계-장기수선충당금-정산-5분" tabindex="-1">2단계: 장기수선충당금 정산 (5분) <a class="header-anchor" href="#_2단계-장기수선충당금-정산-5분" aria-label="Permalink to &quot;2단계: 장기수선충당금 정산 (5분)&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 입주자 &gt; <a href="/occp/move-out.html">전출처리</a> &gt; 장기수선충당금 (OCCP2015)</p></blockquote><p>입주 기간 동안 납부한 장기수선충당금의 환급액을 계산합니다.</p><h4 id="절차-1" tabindex="-1">절차 <a class="header-anchor" href="#절차-1" aria-label="Permalink to &quot;절차&quot;">​</a></h4><ol><li>장기수선충당금 화면 진입</li><li>정산 기간 설정</li><li><strong>처리</strong> 클릭 → 시스템이 자동 계산</li><li>정산 내역 확인: <ul><li>입주 기간</li><li>총 납부 금액</li><li>환급 금액</li></ul></li><li>확인서 출력 (필요 시)</li></ol><div class="tip custom-block"><p class="custom-block-title">정산 기준</p><p>2022년 1월 13일 이후는 <strong>월 단위</strong> 기준으로 계산됩니다.</p></div><h3 id="_3단계-전출-처리-실행-3분" tabindex="-1">3단계: 전출 처리 실행 (3분) <a class="header-anchor" href="#_3단계-전출-처리-실행-3분" aria-label="Permalink to &quot;3단계: 전출 처리 실행 (3분)&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 입주자 &gt; <a href="/occp/move-out.html">전출처리</a> &gt; 전출처리 (OCCP2020)</p></blockquote><h4 id="절차-2" tabindex="-1">절차 <a class="header-anchor" href="#절차-2" aria-label="Permalink to &quot;절차&quot;">​</a></h4><ol><li>전출처리 화면 진입</li><li><strong>동·호수</strong>와 <strong>전출일자</strong> 입력</li><li>시스템이 체납 현황 표시 → 체납이 있으면 먼저 정산</li><li><strong>중간정산</strong> 클릭: <ul><li>전출일까지의 관리비를 일할 계산</li><li>장기수선충당금 환급액 확인</li></ul></li><li>정산 내역 확인 후 <strong>전출 처리</strong> 실행</li><li>중간정산서 출력</li></ol><div class="warning custom-block"><p class="custom-block-title">전출 후 복구</p><p>전출 처리 후 되돌리기가 어렵습니다. 정산 내역을 충분히 확인한 후 실행하세요.</p></div><h3 id="_4단계-관리비예치금-환급-3분" tabindex="-1">4단계: 관리비예치금 환급 (3분) <a class="header-anchor" href="#_4단계-관리비예치금-환급-3분" aria-label="Permalink to &quot;4단계: 관리비예치금 환급 (3분)&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 입주자 &gt; <a href="/occp/move-in.html">입주처리</a> &gt; 관리비예치금(선수관리) (OCCP1040)</p></blockquote><ol><li>해당 세대의 예치금 내역 확인</li><li>환급 처리</li><li>환급 영수증 출력</li></ol><h3 id="_5단계-차량·카드-정리-2분" tabindex="-1">5단계: 차량·카드 정리 (2분) <a class="header-anchor" href="#_5단계-차량·카드-정리-2분" aria-label="Permalink to &quot;5단계: 차량·카드 정리 (2분)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>항목</th><th>메뉴 경로</th></tr></thead><tbody><tr><td>차량 등록 해제</td><td><a href="/occp/">입주자</a> &gt; <a href="/occp/vehicle.html">차량관리</a></td></tr><tr><td>출입카드 회수/비활성화</td><td><a href="/occp/move-in.html">입주처리</a> &gt; 출입카드발급등록</td></tr></tbody></table><hr><h2 id="전입-전출-현황-조회" tabindex="-1">전입/전출 현황 조회 <a class="header-anchor" href="#전입-전출-현황-조회" aria-label="Permalink to &quot;전입/전출 현황 조회&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 입주자 &gt; <a href="/occp/move-out.html">전출처리</a> &gt; 전입/전출자현황 (OCCP2010)</p></blockquote><p>기간별 전입·전출 내역을 조회할 수 있습니다.</p><ul><li>필터: 전입/전출 구분, 기간 설정</li><li>세대 선택 시 상세 정보 확인</li></ul><hr><h2 id="소유주-변경-매매" tabindex="-1">소유주 변경 (매매) <a class="header-anchor" href="#소유주-변경-매매" aria-label="Permalink to &quot;소유주 변경 (매매)&quot;">​</a></h2><p>아파트 매매로 소유자만 변경되는 경우 (입주자는 동일):</p><blockquote><p><strong>메뉴 경로</strong>: 입주자 &gt; <a href="/occp/move-in.html">입주처리</a> &gt; 소유주변동처리</p></blockquote><ol><li>해당 세대 선택</li><li>새 소유자 정보 입력</li><li><strong>저장</strong> → 시스템에 자동 반영</li></ol><hr><h2 id="체크리스트" tabindex="-1">체크리스트 <a class="header-anchor" href="#체크리스트" aria-label="Permalink to &quot;체크리스트&quot;">​</a></h2><h3 id="전입-시" tabindex="-1">전입 시 <a class="header-anchor" href="#전입-시" aria-label="Permalink to &quot;전입 시&quot;">​</a></h3><ul><li>[ ] 이전 세대주 전출 처리가 완료되었는가?</li><li>[ ] 입주자 정보(이름, 연락처, 가족 등)를 정확히 입력했는가?</li><li>[ ] 차량을 등록했는가?</li><li>[ ] 관리비예치금(선수관리비)을 수납했는가?</li><li>[ ] 부과그룹에 포함되어 있는가?</li><li>[ ] 자동이체 신청을 했는가?</li><li>[ ] 개인정보 동의서를 받았는가?</li></ul><h3 id="전출-시" tabindex="-1">전출 시 <a class="header-anchor" href="#전출-시" aria-label="Permalink to &quot;전출 시&quot;">​</a></h3><ul><li>[ ] 미납 관리비가 모두 정산되었는가?</li><li>[ ] 장기수선충당금 환급액을 계산했는가?</li><li>[ ] 중간정산(일할 관리비)을 완료했는가?</li><li>[ ] 관리비예치금을 환급했는가?</li><li>[ ] 차량 등록을 해제했는가?</li><li>[ ] 출입카드를 회수/비활성화했는가?</li><li>[ ] 정산서를 출력·교부했는가?</li></ul><hr><h2 id="자주-발생하는-문제" tabindex="-1">자주 발생하는 문제 <a class="header-anchor" href="#자주-발생하는-문제" aria-label="Permalink to &quot;자주 발생하는 문제&quot;">​</a></h2><h3 id="전출-처리가-안-돼요" tabindex="-1">전출 처리가 안 돼요 <a class="header-anchor" href="#전출-처리가-안-돼요" aria-label="Permalink to &quot;전출 처리가 안 돼요&quot;">​</a></h3><p><strong>원인</strong>: 해당 세대에 미납 관리비가 남아 있는 경우 <strong>해결</strong>: <a href="/recp/overdue.html">미납조회</a>에서 체납 내역을 확인하고, 먼저 수납 처리하세요.</p><h3 id="전출-세대의-미수금을-새-입주자에게-청구해도-되나요" tabindex="-1">전출 세대의 미수금을 새 입주자에게 청구해도 되나요? <a class="header-anchor" href="#전출-세대의-미수금을-새-입주자에게-청구해도-되나요" aria-label="Permalink to &quot;전출 세대의 미수금을 새 입주자에게 청구해도 되나요?&quot;">​</a></h3><p><strong>아닙니다.</strong> 이전 세대주의 미수금은 <strong>이전 세대주 본인</strong>에게 청구해야 합니다. 새 입주자에게 전가할 수 없습니다.</p><h3 id="중간정산-금액이-이상해요" tabindex="-1">중간정산 금액이 이상해요 <a class="header-anchor" href="#중간정산-금액이-이상해요" aria-label="Permalink to &quot;중간정산 금액이 이상해요&quot;">​</a></h3><p><strong>원인</strong>: 전출일 기준 일할 계산 오류, 검침 미반영 등 <strong>해결</strong>: 전출일이 정확한지 확인하고, 해당 월 검침이 완료되었는지 확인하세요.</p><h3 id="매매인데-전출입을-해야-하나요" tabindex="-1">매매인데 전출입을 해야 하나요? <a class="header-anchor" href="#매매인데-전출입을-해야-하나요" aria-label="Permalink to &quot;매매인데 전출입을 해야 하나요?&quot;">​</a></h3><p>소유자만 변경되고 입주자가 동일하면 <strong>소유주변동처리</strong>만 하면 됩니다. 입주자(임차인)까지 변경되면 전출입 처리가 필요합니다.</p><hr><h2 id="관련-메뉴" tabindex="-1">관련 메뉴 <a class="header-anchor" href="#관련-메뉴" aria-label="Permalink to &quot;관련 메뉴&quot;">​</a></h2><ul><li><a href="/occp/move-in.html">입주처리</a> - 입주 등록·예치금·카드</li><li><a href="/occp/move-out.html">전출처리</a> - 전출 정산·충당금</li><li><a href="/occp/vehicle.html">차량관리</a> - 차량 등록/해제</li><li><a href="/occp/privacy.html">개인정보</a> - 개인정보 관리</li><li><a href="/recp/overdue.html">미납조회</a> - 미납 확인</li><li><a href="/impo/basic.html">기초정보</a> - 부과그룹·자동이체</li></ul>`,78)])])}const g=l(e,[["render",r]]);export{u as __pageData,g as default};
